INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('d889211f027bcd82', 'NV', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in Nevada for the 2026 cycle?', '["Are Catherine Cortez Masto or Jacky Rosen up for re-election in 2026?","When is the next US Senate election in NV?","2026 Nevada Senate candidates"]', 'No. There is no U.S. Senate race in Nevada in 2026. Senator Catherine Cortez Masto (Class 3) is next up for re-election in 2028, and Senator Jacky Rosen (Class 1) is next up in 2030.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State – Elections', '2026-05-12', 'per_cycle', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('6929be8a5c0d3f00', 'NV', '["state"]', 'candidate_eligibility', 'Is Governor Joe Lombardo running for re-election in 2026?', '["Is the Nevada Governor''s seat open in 2026?","Who is running for Nevada Governor in 2026?","Joe Lombardo 2026 re-election intent"]', 'Yes. Governor Joe Lombardo (R), who was elected in 2022, is eligible for and seeking re-election to a second term in 2026.', 'https://www.nvsos.gov/sos/elections/candidates', 'Nevada Secretary of State – Candidates', '2026-05-12', 'volatile', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('749e650ab6c07ec5', 'NV', '["state"]', 'election_dates', 'Which Nevada statewide executive offices are up for election in 2026?', '["Who is on the ballot in Nevada in 2026?","Is the Attorney General up for reelection?","2026 Nevada state executive elections"]', 'All six of Nevada''s constitutional executive offices are on the 2026 ballot: Governor, Lieutenant Governor, Attorney General, Secretary of State, State Treasurer, and State Controller.', 'https://www.nvsos.gov/sos/elections/candidates', 'Nevada Secretary of State – Election Information', '2026-05-12', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('c71a1328ed7cc910', 'NV', '["federal","state","county"]', 'runoff_rules', 'Does Nevada use ranked-choice voting (RCV) and open primaries in 2026?', '["Did Question 3 pass in Nevada?","Are Nevada primaries open to independents?","Nevada final-five voting 2026"]', 'No. Ballot Question 3, which would have established open primaries and ranked-choice voting for general elections, was rejected by voters in 2024. Because constitutional amendments require passage in two consecutive general elections, its 2022 initial approval was nullified, maintaining the status quo.', 'https://www.nvsos.gov/sos/elections/election-information/2024-election-information', 'Nevada Secretary of State – 2024 Election Results', '2026-05-12', 'static', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('f32cff0015e04ff0', 'NV', '["federal","state","county"]', 'voter_interaction', 'Are Nevada primary elections closed or open?', '["Can nonpartisan voters vote in the Nevada primary?","Do I have to register with a party to vote in the primary?","Closed partisan primary NV"]', 'Nevada holds strictly closed partisan primaries. Only voters registered with a major political party may vote in that party''s primary election for partisan offices.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec175', 'NRS 293.175', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('2655e5af6aa72b2e', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote in Nevada in 2026?', '["Nevada voter ID laws 2026","Did Question 7 pass?","Do I need my driver''s license to vote in NV?"]', 'Currently, Nevada does not require photo ID to vote if a voter''s signature matches their registration. However, voters passed Question 7 (a photo ID requirement) in 2024. Because it is a constitutional amendment, it must pass a second time on the 2026 ballot to take effect.', 'https://www.nvsos.gov/sos/elections/voters/election-day-voting', 'Nevada Secretary of State – Voting', '2026-05-12', 'volatile', 'official_source_direct', 'All voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('466bc1365efb51c1', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does every voter in Nevada automatically receive a mail-in ballot?', '["Universal mail voting Nevada","Do I have to request an absentee ballot in NV?","AB 321 mail ballots"]', 'Yes. Under AB 321, codified in NRS 293.269911, every active registered voter in Nevada is automatically mailed a ballot for every election unless they explicitly submit a form to opt out.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec269911', 'NRS 293.269911', '2026-05-12', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('5e910308d8efc3dd', 'NV', '["federal","state","county","municipal","judicial"]', 'election_dates', 'What is the deadline for a mail-in ballot to be received and counted in Nevada?', '["When is my absentee ballot due in NV?","Nevada mail ballot postmark rule","4-day receipt deadline for ballots"]', 'A mail-in ballot will be counted if it is postmarked on or before Election Day and received by the county clerk no later than 5:00 p.m. on the fourth day following the election.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec269921', 'NRS 293.269921(2)', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('4f00d82385f1eab0', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Nevada allow same-day voter registration?', '["Can I register to vote at the polls in Nevada?","Same-day registration rules NV","Election day registration Nevada"]', 'Yes. Nevada offers same-day voter registration. Eligible citizens can register to vote and cast a ballot in person at any polling location during the early voting period or on Election Day, using a valid Nevada driver''s license or ID card.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec5772', 'NRS 293.5772', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('c3866889b500a18e', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How does Automatic Voter Registration (AVR) work in Nevada?', '["Are you automatically registered to vote at the DMV in NV?","Question 5 AVR implementation","Motor voter rules Nevada"]', 'Nevada utilizes an Automatic Voter Registration (AVR) system. Under NRS 293.5727, any eligible citizen who completes a transaction at the DMV is automatically registered to vote unless they explicitly decline at the point of service.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec5727', 'NRS 293.5727', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('3045d7303d5240dc', 'NV', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Nevada Primary Election?', '["What date is the NV primary in 2026?","Nevada 2026 primary date","When do polls open for the NV primary?"]', 'The Nevada Primary Election is on Tuesday, June 9, 2026. Under NRS 293.175, the primary election is statutorily held on the second Tuesday in June.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec175', 'NRS 293.175', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('2b453c6de54af6c7', 'NV', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Nevada General Election?', '["What date is the NV general election in 2026?","NV 2026 midterm election date","When is Election Day 2026 in Nevada?"]', 'The Nevada General Election is on Tuesday, November 3, 2026.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State – Elections', '2026-05-12', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('906b03b9a3c20ab3', 'NV', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for partisan candidates for the 2026 Nevada primary?', '["When did candidates have to file for the 2026 primary in Nevada?","Declaration of candidacy deadline 2026","Nevada March filing deadline"]', 'For partisan candidates, the filing period for declarations of candidacy opened on the first Monday in March and closed at 5:00 p.m. on the second Friday following the first Monday in March (March 2 to March 13, 2026).', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec177', 'NRS 293.177(1)(b)', '2026-05-12', 'per_cycle', 'statute_citation', 'Major party candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('4ab1bd4c313ddd56', 'NV', '["federal","state","county"]', 'filing_requirements', 'When is the filing deadline for Independent candidates in Nevada for 2026?', '["Running as an independent in NV","Independent ballot access deadline Nevada","When are nonparty petitions due?"]', 'Independent candidates who wish to bypass the partisan primary and appear on the general election ballot must file their petition of candidacy no later than the third Friday in June (June 19, 2026).', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec200', 'NRS 293.200(4)', '2026-05-12', 'per_cycle', 'statute_citation', 'Independent candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('44d45ff6a4c3436b', 'NV', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'What are the candidate filing fees in Nevada?', '["How much does it cost to run for office in NV?","Nevada filing fee schedule 2026","Does Nevada charge a filing fee for candidates?"]', 'Nevada has a graduated filing fee schedule. U.S. Senator is $500; U.S. House, Governor, and Supreme Court Justice are $300; other statewide executive offices are $200; District Judge is $150; State Senate, State Assembly, and Justice of the Peace are $100; and other district or county offices are $30.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec193', 'NRS 293.193', '2026-05-12', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('9f31dbe8aa175047', 'NV', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor in Nevada?', '["How old do you have to be to be NV Governor?","Gubernatorial candidate residency rules","Do I have to live in Nevada for 5 years to run for Governor?"]', 'Under the Nevada Constitution, a candidate for Governor must be a qualified elector, at least 25 years old at the time of the election, and a resident citizen of Nevada for at least two years immediately preceding the election.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art5Sec3', 'Nevada Constitution Article 5 § 3', '2026-05-12', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('16707c93d7bc76cc', 'NV', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Nevada State Legislature?', '["How old to run for State Senate NV?","Residency rules State Assembly Nevada","Do I have to live in the district to run for Assembly?"]', 'A candidate for the Nevada State Senate or State Assembly must be a qualified elector, at least 21 years old at the time of the election, and a resident citizen of the state for at least one year immediately preceding the election.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art4Sec5', 'Nevada Constitution Article 4 § 5', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('c7b7e0c5313fc80a', 'NV', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. House in Nevada?', '["Do I have to live in the district to run for Congress in NV?","Congressional age limit Nevada","US House qualifications"]', 'Under the U.S. Constitution, a candidate for the U.S. House of Representatives must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of Nevada when elected. District residency is not required.', 'https://www.nvsos.gov/sos/elections/candidates', 'Nevada Secretary of State / U.S. Constitution Art. I § 2', '2026-05-12', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('beeedf79352fa298', 'NV', '["state","county","municipal","judicial"]', 'recall_rules', 'What is the operational process for a recall election in Nevada?', '["How does a recall election work in NV?","Can a recalled politician resign before the election?","Nevada recall ballot rules"]', 'A recall can be triggered after six months in office with signatures equal to 25% of the votes cast in the last election for that office. Once a petition is verified, the targeted official has 5 days to resign. If they do not, a special election is scheduled within 30 days. Other candidates may appear on the ballot, and a plurality winner takes the unexpired term.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art2Sec9', 'Nevada Constitution Article 2 § 9', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('146634191916579f', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'When does early voting (in-person) begin in Nevada?', '["When can I vote early in NV?","In-person early voting window","Nevada early voting duration"]', 'In-person early voting in Nevada runs for a statutorily mandated 14 days. It begins on the Saturday that is 17 days before the election and concludes on the Friday immediately preceding Election Day.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec3568', 'NRS 293.3568', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('46282f67b03bfa47', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Are secure drop boxes for absentee ballots legally mandated in Nevada?', '["Can I put my absentee ballot in a drop box in NV?","Mail ballot drop boxes Nevada","Does Nevada use drop boxes for voting?"]', 'Yes. Under AB 321, Nevada law requires county and city clerks to establish secure mail ballot drop boxes at every polling place during the early voting period and on Election Day, protecting the practice from localized placement disputes.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec269927', 'NRS 293.269927', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('3cc570b70b70d8cf', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the deadline to cure a mail ballot signature in Nevada?', '["When do I have to fix my signature for my mail ballot?","Absentee ballot curing window NV","Nevada mail ballot signature mismatch"]', 'If a mail ballot signature is missing or does not match the registration record, the county clerk must notify the voter. The voter has until 5:00 p.m. on the sixth day following the election to cure the defect by providing a signature confirmation.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec269927', 'NRS 293.269927', '2026-05-12', 'static', 'statute_citation', 'Voters and Poll Watchers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('e7205d60af54a11f', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'Can a corporation contribute directly to a candidate for state office in Nevada?', '["Are corporate contributions legal in NV?","Can my business donate to a state candidate?","LLC donation rules Nevada"]', 'Yes. Nevada permits direct corporate treasury contributions to candidates. Corporations and LLCs are treated as "persons" and are subject to the same strict individual limits of $5,000 for the primary and $5,000 for the general election ($10,000 per cycle). There is no automatic inflation adjustment for these limits.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec100', 'NRS 294A.100', '2026-05-12', 'static', 'statute_citation', 'Corporations, LLCs, and Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('5d997d49f8ccaa51', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the PAC contribution limits for Nevada state campaigns?', '["How much can a PAC give to a candidate in NV?","PAC contribution limits Nevada","Super PAC direct donation rules"]', 'Political Action Committees (PACs) in Nevada may receive unlimited contributions, but they are subject to the exact same per-candidate contribution limits as individuals: $5,000 for the primary and $5,000 for the general election.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec100', 'NRS 294A.100', '2026-05-12', 'static', 'statute_citation', 'PACs and Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('e8686e30946e62af', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the Contributions and Expenses (C&E) reporting schedule in Nevada?', '["When are campaign finance reports due in NV?","C&E report deadlines Nevada","Nevada periodic campaign filing dates"]', 'Candidates must file Contributions & Expenses (C&E) reports electronically through the Aurora system. During an election year, reports are due pre-primary, pre-general, and post-general. Additionally, an Annual Report is due by January 15 of each year.', 'https://www.nvsos.gov/sos/elections/candidate-information', 'Nevada Secretary of State – Candidate Information', '2026-05-12', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('b25af6314c0bcef7', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the itemized disclosure threshold for campaign contributions in Nevada?', '["When do I have to list a donor''s name in NV?","Campaign contribution disclosure limit","Nevada $100 donation rule"]', 'Any campaign contribution in excess of $100 must be individually itemized on the candidate''s Contributions & Expenses (C&E) report, disclosing the contributor''s name and address.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec120', 'NRS 294A.120', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('14085833c6366597', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'Are anonymous campaign contributions permitted in Nevada?', '["Can I donate cash anonymously in NV?","Anonymous contribution cap Nevada","Passing the hat rules campaign finance"]', 'No. Under NRS 294A.190, candidates are strictly prohibited from accepting anonymous contributions of $100 or more. Any prohibited anonymous contribution must be remitted to the State Treasurer for deposit in the State General Fund.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec190', 'NRS 294A.190', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('90cd49095a404b29', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'Are candidates required to open a separate bank account for their campaign in Nevada?', '["Campaign bank account rules NV","Can I use my personal checking account for donations?","Nevada campaign depository requirements"]', 'Yes. Under Nevada law, any candidate who receives $1,000 or more in aggregate contributions must open a separate campaign depository account at a financial institution. Commingling campaign funds with personal or business funds is prohibited.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec130', 'NRS 294A.130', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers and Candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('674d12c29567a24e', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'Can a donor give money to a Nevada campaign through another person?', '["Conduit reporting mechanism NV","Straw donor prohibition Nevada","Making contributions in the name of another"]', 'No. NRS 294A.112 strictly prohibits making a contribution in the name of another person (straw donor) and prohibits any candidate from knowingly accepting a contribution made by a person in the name of another.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec112', 'NRS 294A.112', '2026-05-12', 'static', 'statute_citation', 'Donors and Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('3db6218457c3d302', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'Do campaign contribution limits apply during a recall election in Nevada?', '["Recall financing limits Nevada","Can a recalled politician raise unlimited money?","Recall contribution caps NV"]', 'Yes. A separate contribution limit applies specifically to special recall elections in Nevada. Donors may contribute up to an additional $5,000 to a candidate in a recall election, which is entirely distinct from and does not affect the standard $10,000 primary/general election cycle limits.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec115', 'NRS 294A.115', '2026-05-12', 'static', 'statute_citation', 'Incumbent officials facing recall', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('7416571b50dd47d6', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does a mail-in ballot require a witness signature in Nevada?', '["Who can witness an absentee ballot in NV?","Does someone have to watch me vote by mail?","Nevada mail ballot witness requirement"]', 'No. Unlike some other states, Nevada does not require a witness signature or a notary public to validate a mail-in ballot. The ballot is verified exclusively by matching the voter''s signature on the return envelope against their voter registration record.', 'https://www.nvsos.gov/sos/elections/voters/mail-ballot-voting', 'Nevada Secretary of State – Mail Ballot Voting', '2026-05-12', 'static', 'official_source_direct', 'Absentee voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('3fa830ee29b19536', 'NV', '["federal"]', 'election_dates', 'How are vacancies in the U.S. Senate filled in Nevada?', '["Who replaces a US Senator from Nevada?","Does the Governor appoint Senate vacancies in NV?","Special election for US Senate"]', 'If a U.S. Senate seat becomes vacant, the Governor appoints a replacement to serve an interim term. A special election is then scheduled to fill the remainder of the unexpired term.', 'https://www.leg.state.nv.us/nrs/nrs-304.html#NRS304Sec030', 'NRS 304.030', '2026-05-12', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('982a981f211f38e1', 'NV', '["federal"]', 'election_dates', 'How are vacancies in the U.S. House of Representatives filled in Nevada?', '["Does the Governor appoint US House vacancies?","Special election for Congress NV","Congressional vacancy fill Nevada"]', 'Vacancies in the U.S. House can only be filled by a special election called by a proclamation from the Governor. The Governor does not have the authority to appoint an interim Representative.', 'https://www.leg.state.nv.us/nrs/nrs-304.html#NRS304Sec050', 'NRS 304.050', '2026-05-12', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('3c5e944c6851e65c', 'NV', '["state"]', 'election_dates', 'How are vacancies in the Nevada State Legislature filled?', '["Special election for State Assembly NV","Does the Governor appoint state senators?","Legislative vacancy fill Nevada"]', 'Legislative vacancies in Nevada are filled by an appointment from the board of county commissioners. The appointee must be a member of the same political party as the former legislator. If the district spans multiple counties, the commissioners from each county meet jointly and cast a proportional vote based on the district''s population within their respective counties.', 'https://www.leg.state.nv.us/nrs/nrs-218a.html#NRS218ASec260', 'NRS 218A.260', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates and County Commissioners', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('5d8c44bfc7827949', 'NV', '["federal","state","county","municipal"]', 'ballot_access', 'What is the procedure for running as a write-in candidate in Nevada?', '["Do write-in candidates have to register in NV?","How to legally canvass write-in votes","Write-in voting line on the ballot"]', 'Write-in candidacies are strictly prohibited in Nevada. Under state law, voting must be only upon candidates whose names appear printed on the ballot, and no person may write in the name of an additional candidate for any office.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec270', 'NRS 293.270(2)', '2026-05-12', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('c4e6088665f0f868', 'NV', '["federal","state","county"]', 'ballot_access', 'What is the signature requirement for a minor political party to gain ballot access in Nevada?', '["How to form a new political party NV","Signatures needed for third party ballot access","Party qualification threshold Nevada"]', 'To qualify a minor political party for ballot access, organizers must file a petition containing valid signatures equal to at least 1% of the total votes cast for U.S. House of Representatives in the state at the preceding general election.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec1715', 'NRS 293.1715', '2026-05-12', 'per_cycle', 'statute_citation', 'Third-party organizers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('f31aa6b50fca6302', 'NV', '["judicial"]', 'election_dates', 'How are justices selected for the Nevada Supreme Court and Court of Appeals?', '["Are Supreme Court judges elected in NV?","Nevada judicial elections partisan","How long do NV highest court judges serve?"]', 'The Nevada Supreme Court (7 justices) and the Court of Appeals (3 judges, created in 2014) are elected in statewide nonpartisan elections to serve six-year terms. Mid-term vacancies are filled by gubernatorial appointment from a list provided by the Commission on Judicial Selection.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art6Sec3', 'Nevada Constitution Article 6 § 3', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('078cb83e2ed56aa1', 'NV', '["federal","state"]', 'redistricting', 'Which state legislative and congressional maps are in effect for the 2026 Nevada elections?', '["Did Nevada redraw its assembly districts for 2026?","Who drew the redistricting maps","Are we using an independent commission for the state legislature?"]', 'The 2026 elections use the maps drawn and passed by the Nevada Legislature in 2021. Nevada does not have an independent redistricting commission. The state comprises 4 U.S. House districts, 21 State Senate districts, and 42 State Assembly districts.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'State Legislative and U.S. House candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('604f227a3894ad36', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the polling place electioneering buffer zone in Nevada?', '["How close to the door can I campaign in NV?","100-foot rule Nevada voting","Campaign signs at polling places"]', 'Nevada enforces a strict 100-foot electioneering buffer zone measured from the entrance to the voting area of a polling place. No campaigning, solicitation, or distribution of political materials is permitted within this boundary.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec740', 'NRS 293.740', '2026-05-12', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('06e86656bfc4bdce', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Nevada law require employers to give time off to vote?', '["Do I get paid time off to vote in NV?","Employee voting leave Nevada","1 to 3 hours off to vote rule"]', 'Yes. If it is impractical for a voter to vote before or after work, employers must grant 1 to 3 hours of paid time off to vote, depending on the distance between the workplace and the polling place.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec463', 'NRS 293.463', '2026-05-12', 'static', 'statute_citation', 'Voters and Employers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('21ca1dcf7104e669', 'NV', '["county"]', 'election_dates', 'When are County Commissioners elected in Nevada?', '["Are county commission races partisan in NV?","County Commissioner term length","Local executive elections"]', 'County Commissioners in Nevada are elected in partisan elections to serve four-year terms. They function as the governing body for county-level administration.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'County-level Candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('7ffbc8eda69580ad', 'NV', '["state"]', 'candidate_eligibility', 'What are the specific qualifications to run for Attorney General in Nevada?', '["How old do I need to be to run for Attorney General in NV?","Does the Attorney General have to be a lawyer in Nevada?","Attorney General residency rules"]', 'A candidate for Nevada Attorney General must be a qualified elector, at least 30 years of age, a resident citizen of the state for three years immediately preceding the election, and a member of the State Bar of Nevada in good standing.', 'https://www.leg.state.nv.us/nrs/NRS-228.html#NRS228Sec010', 'NRS 228.010', '2026-05-12', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('9120fa51a747d4ce', 'NV', '["state"]', 'candidate_eligibility', 'What are the specific qualifications to run for Secretary of State in Nevada?', '["How old do I need to be to run for Secretary of State?","Secretary of State residency rules Nevada","Candidate eligibility for SoS NV"]', 'A candidate for Nevada Secretary of State must be a qualified elector (registered to vote), at least 25 years of age at the time of the election, and a resident citizen of the state for two years immediately preceding the election.', 'https://www.leg.state.nv.us/nrs/NRS-225.html#NRS225Sec010', 'NRS 225.010', '2026-05-12', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('9b5054a72eab9343', 'NV', '["judicial"]', 'candidate_eligibility', 'What are the qualifications to run for the Nevada Supreme Court?', '["Do Supreme Court justices have to be lawyers in NV?","Nevada judicial qualifications","How long must I practice law to be a judge?"]', 'A candidate for the Nevada Supreme Court must be a qualified elector, at least 25 years of age, a resident of Nevada for two years, and an attorney licensed and admitted to practice law for not less than 15 years (at least two of which must be in Nevada).', 'https://www.leg.state.nv.us/nrs/NRS-002.html#NRS002Sec020', 'NRS 2.020', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('24dea47a562488fb', 'NV', '["judicial"]', 'candidate_eligibility', 'What are the qualifications to run for the Nevada District Court or Court of Appeals?', '["Do district judges have to be lawyers in NV?","Court of appeals candidate requirements","How many years of law practice to be a district judge in Nevada?"]', 'Candidates for the Nevada District Court or Court of Appeals must be at least 25 years old, a two-year resident of Nevada, and licensed to practice law for not less than 10 years (at least two of which must be in Nevada).', 'https://www.nvsos.gov/elections/candidate-information/filing-for-judicial-office', 'Nevada Secretary of State – Judicial Filing', '2026-05-12', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('88e63ce6909c0621', 'NV', '["state"]', 'election_dates', 'Who succeeds the Governor of Nevada in the event of a vacancy?', '["What happens if the NV Governor resigns?","Lieutenant Governor succession Nevada","Gubernatorial vacancy fill"]', 'If a vacancy occurs in the office of the Governor due to death, resignation, or removal, the Lieutenant Governor assumes the powers and duties of the office for the remainder of the unexpired term.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art5Sec17', 'Nevada Constitution Article 5 § 17', '2026-05-12', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('1ca5cd39515fee0d', 'NV', '["judicial"]', 'election_dates', 'How are mid-term vacancies filled in the Nevada court system?', '["Who appoints judges in Nevada?","Commission on Judicial Selection","Judicial vacancy fill process NV"]', 'When a mid-term vacancy occurs in the Supreme Court, Court of Appeals, or District Court, the Commission on Judicial Selection conducts interviews and provides a list of three nominees to the Governor, who then must appoint one to serve until the next general election.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art6Sec20', 'Nevada Constitution Article 6 § 20', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates and Legal Counsel', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('fe20398f7a6b6ae1', 'NV', '["state"]', 'election_dates', 'How are vacancies filled for Nevada''s Attorney General, Secretary of State, or State Treasurer?', '["Does the Governor appoint the AG in NV?","Vacancy fill for statewide executive offices","Who replaces the Secretary of State?"]', 'If a vacancy occurs in a statewide executive office (such as Attorney General, Secretary of State, Treasurer, or Controller), the Governor has the authority to appoint an interim replacement to serve out the remainder of the unexpired term or until the next general election.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art5Sec8', 'Nevada Constitution Article 5 § 8', '2026-05-12', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('1650d82e7cd87e59', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'Are candidates in Nevada allowed to use campaign funds for personal expenses?', '["Personal use of campaign funds NV","Can I buy a car with campaign money?","Nevada rules on spending campaign donations"]', 'No. Under Nevada law, it is strictly prohibited to convert campaign contributions to personal use. Expenses must be directly related to the campaign or the execution of public office duties.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec160', 'NRS 294A.160', '2026-05-12', 'static', 'statute_citation', 'All candidates and treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('67bd2d76b642f49f', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the rules for disposing of surplus campaign funds in Nevada?', '["Surplus funds disposition NV","Can I give my leftover campaign money to charity?","What happens to campaign money when I close my committee?"]', 'Unspent campaign funds in Nevada cannot be kept for personal use. They must be returned to contributors, used in the candidate''s next election, donated to a tax-exempt nonprofit, contributed to a political party, or donated to a government entity.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec160', 'NRS 294A.160', '2026-05-12', 'static', 'statute_citation', 'Candidates concluding campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('bc58968d2919054f', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'How are independent expenditures disclosed in Nevada?', '["When does an independent group have to file?","Independent expenditure reporting NV","Aurora independent expenditure schedules"]', 'Any person or committee making independent expenditures must report those expenses electronically via the Secretary of State''s Aurora system, adhering to the same standard pre-election and annual reporting schedule as candidates if their spending exceeds the required statutory thresholds.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec140', 'NRS 294A.140', '2026-05-12', 'static', 'statute_citation', 'Super PACs and Independent Expenditure Committees', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('4856ff29c3ee1edc', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the penalties for filing a campaign finance report late with the Nevada Secretary of State?', '["Late filing fees NV","How much is the fine for missing a reporting deadline?","Aurora C&E report late penalties"]', 'The Secretary of State can assess civil penalties for late Contributions & Expenses (C&E) reports. The fine is tiered based on the number of days late and can reach up to a maximum penalty of $5,000 for a severe delinquency.', 'https://www.leg.state.nv.us/nrs/nrs-294a.html#NRS294ASec420', 'NRS 294A.420', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('9cbde89a89232496', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the criminal penalties for voter intimidation in Nevada?', '["Is voter intimidation a felony in NV?","Election interference laws Nevada","NRS 293.710 intimidation rules"]', 'Under NRS 293.710, using force, coercion, or intimidation to impede or prevent the free exercise of the franchise by any voter, or interfering with election officials, is a Category E felony punishable by prison time.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec710', 'NRS 293.710', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('01b17b299d2b8815', 'NV', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the rules for poll observers in Nevada?', '["Can I watch the vote counting in NV?","Poll watcher requirements Nevada","Do election observers need to sign a form?"]', 'Poll observers are permitted inside polling places, but they must sign an acknowledgment form agreeing to abide by state laws, remain in designated observation areas, and strictly avoid interfering with the voting process or election workers.', 'https://www.nvsos.gov/sos/elections/election-information/election-observers', 'Nevada Secretary of State – Election Observers', '2026-05-12', 'static', 'official_source_direct', 'Poll watchers and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('f429dad664287c23', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the pre-registration deadline for mail-in or online voter registration in Nevada?', '["When is the last day to register online to vote in NV?","17-day registration rule Nevada","Voter registration deadline prior to same-day"]', 'Standard online and mail-in voter registration closes 17 days before the election. Individuals who miss this deadline may still utilize same-day registration at early voting locations or polling places on Election Day.', 'https://www.nvsos.gov/sos/elections/voters/registering-to-vote', 'Nevada Secretary of State – Voter Registration', '2026-05-12', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('1fd1f597dd97cb2c', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How are inactive voters removed from the registration rolls in Nevada?', '["Voter roll purges NV","How many elections can I miss before my registration is cancelled?","NVRA list maintenance Nevada"]', 'Under the NVRA list maintenance framework, a voter is designated ''inactive'' if election mail bounces. If an inactive voter does not respond to a forward notice and subsequently fails to vote in two consecutive federal general elections, their registration is legally cancelled.', 'https://www.nvsos.gov/sos/elections/voters/list-maintenance', 'Nevada Secretary of State – List Maintenance', '2026-05-12', 'static', 'official_source_direct', 'Voters and Election Officials', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('c5fc009552329c3c', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can private groups set up unauthorized drop boxes for mail-in ballots in Nevada?', '["Are private ballot drop boxes legal in NV?","Who controls mail ballot drop boxes?","NRS 293.730 unauthorized boxes"]', 'No. Under Nevada law, it is strictly prohibited for anyone other than a county or city clerk to establish or operate a mail ballot drop box. Unauthorized collection boxes are illegal.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec730', 'NRS 293.730', '2026-05-12', 'static', 'statute_citation', 'Campaigns and Political Parties', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('8b6f2dc215a61119', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Who acts as the chief elections official in Clark and Washoe counties?', '["Does the county clerk run elections in Las Vegas?","Clark County Registrar of Voters","Washoe county election administration"]', 'In Nevada''s two most populous counties, Clark (Las Vegas) and Washoe (Reno), election administration is handled by an appointed Registrar of Voters rather than the elected County Clerk. The Registrar manages all voter registration and ballot processing for their respective jurisdiction.', 'https://www.clarkcountynv.gov/government/departments/elections/index.php', 'Clark County Election Department', '2026-05-12', 'static', 'secondary_source', 'Candidates and Consultants', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('d88a1858075ec3fd', 'NV', '["municipal"]', 'election_dates', 'Are mayoral and city council elections partisan in Nevada?', '["Do mayors run with a party label in NV?","City council partisan elections Nevada","Municipal election structure"]', 'No. Mayoral, city council, and local school board elections in Nevada are strictly nonpartisan. Candidates appear on the ballot without a political party affiliation next to their name.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Municipal and School Board candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('1a25e5b4946da65e', 'NV', '["special_district"]', 'election_dates', 'Are local school board elections partisan in Nevada?', '["School board trustee elections NV","Do school board candidates run with a party label?","Education board election structure"]', 'Local school board trustee elections in Nevada are statutorily nonpartisan. Candidates do not run with a political party affiliation and the races do not involve partisan primaries.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'School Board candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('d3d354a700a3fbd2', 'NV', '["county"]', 'election_dates', 'Are County Sheriff and District Attorney elections partisan in Nevada?', '["Is the sheriff race partisan in NV?","District Attorney election schedule","County executive officer terms"]', 'Yes. County Sheriffs and District Attorneys are elected in partisan elections to serve four-year terms, meaning candidates run with a designated political party affiliation.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'County-level candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('243bcd4fc7036b45', 'NV', '["state"]', 'election_dates', 'What is the structure of the Nevada Legislature''s session?', '["Does the Nevada legislature meet every year?","Biennial legislative session NV","120-day session limit Nevada"]', 'The Nevada Legislature operates on a biennial schedule, meeting in regular session only during odd-numbered years. The session is constitutionally limited to a maximum of 120 consecutive calendar days.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art4Sec2', 'Nevada Constitution Article 4 § 2', '2026-05-12', 'static', 'statute_citation', 'State Legislators and Consultants', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('b6863a155b4cc851', 'NV', '["state"]', 'election_dates', 'Who can call a special session of the Nevada Legislature?', '["Special session authority NV","Can the legislature convene itself?","Governor proclamation for special session"]', 'The Governor of Nevada has the constitutional authority to convene the Legislature in a special session via proclamation. During a special session, the Legislature may only consider legislation related to the specific purposes set forth by the Governor, unless the legislature calls itself into session with a two-thirds vote.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art5Sec9', 'Nevada Constitution Article 5 § 9', '2026-05-12', 'static', 'statute_citation', 'State Legislators', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('37c58ab55b53d29f', 'NV', '["state"]', 'ballot_access', 'How can citizens amend the Nevada Constitution via initiative?', '["Constitutional amendment process NV","2-cycle initiative requirement","How to change the Nevada constitution by vote"]', 'A citizen-initiated constitutional amendment must be approved by a majority of voters in TWO consecutive even-year general elections before it becomes part of the state constitution (e.g., Question 3''s failure in 2024 after passing in 2022).', 'https://www.leg.state.nv.us/Const/NVConst.html#Art19Sec2', 'Nevada Constitution Article 19 § 2', '2026-05-12', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('1ce557ee97d836a2', 'NV', '["state"]', 'ballot_access', 'How can the Nevada Legislature place a constitutional amendment on the ballot?', '["Legislative referral for constitutional amendment NV","How does the legislature change the NV constitution?","Two-session requirement Nevada"]', 'The Nevada Legislature can refer a constitutional amendment to the voters by passing a joint resolution with a simple majority in TWO consecutive legislative sessions. After passing both sessions, the amendment is placed on the general election ballot for final voter ratification.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art16Sec1', 'Nevada Constitution Article 16 § 1', '2026-05-12', 'static', 'statute_citation', 'State Legislators and Campaigns', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('f656f199045cb6cf', 'NV', '["state"]', 'ballot_access', 'What is the geographic distribution requirement for statutory initiative signatures in Nevada?', '["Do I need signatures from every county in NV?","Initiative geographic distribution rule","10% threshold across congressional districts"]', 'To qualify a statutory initiative, organizers must collect valid signatures equal to 10% of the voters who cast ballots in the last preceding general election. Critically, these signatures must be proportionately distributed, achieving the 10% threshold within each of Nevada''s four separate congressional districts.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art19Sec2', 'Nevada Constitution Article 19 § 2', '2026-05-12', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('38cfde0b1fd47ddd', 'NV', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the NVOTE database?', '["Nevada statewide voter registration system","How are voter rolls managed in NV?","Secretary of State NVOTE database"]', 'NVOTE is the centralized, top-down statewide voter registration database managed by the Nevada Secretary of State. It aggregates registration data from all counties and interfaces with the DMV for Automatic Voter Registration (AVR) processing.', 'https://www.nvsos.gov/sos/elections/voters', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'Election Officials and Consultants', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('59ac968ea5a43e2f', 'NV', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the Aurora campaign finance system?', '["Where do I file my C&E reports electronically?","Nevada Secretary of State Aurora portal","Campaign finance software NV"]', 'Aurora is the Nevada Secretary of State''s mandatory electronic filing system for campaign finance. All candidates and committees must use Aurora to file their Contributions & Expenses (C&E) reports and Financial Disclosure Statements.', 'https://www.nvsos.gov/sos/elections/candidate-information', 'Nevada Secretary of State – Aurora', '2026-05-12', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('1e53123355464de8', 'NV', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'Who can request a recount in a Nevada election?', '["Automatic recount margin Nevada","How to challenge election results in NV","Recount request deposit requirements"]', 'Nevada does not have automatic recounts. Any defeated candidate can demand a recount within 3 working days after the final canvass of the vote. However, the requesting candidate must pay the estimated costs of the recount in advance as a deposit.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec403', 'NRS 293.403', '2026-05-12', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('5b9595a3f0445ba5', 'NV', '["state"]', 'candidate_eligibility', 'What are the term limits for Nevada''s statewide executive officers?', '["How long can someone serve as Secretary of State in NV?","Attorney General term limits","Executive office consecutive terms Nevada"]', 'Under the Nevada Constitution, the Governor, Lieutenant Governor, Secretary of State, State Treasurer, State Controller, and Attorney General are strictly limited to serving two four-year terms in their respective offices.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art5Sec19', 'Nevada Constitution Article 5 § 19', '2026-05-12', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('91a438896270d4c1', 'NV', '["state"]', 'candidate_eligibility', 'What are the term limits for members of the Nevada State Legislature?', '["How long can someone serve in the NV Assembly?","State Representative term limits Nevada","State Senate consecutive terms"]', 'The Nevada Constitution strictly limits state legislators to serving a maximum of 12 years (six terms) in the State Assembly and 12 years (three terms) in the State Senate.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art4Sec3', 'Nevada Constitution Article 4 § 3 & 4', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('14e925d5d3aa0925', 'NV', '["federal"]', 'redistricting', 'How many congressional districts does Nevada have for the 2026 cycle?', '["Number of US House seats in NV","Nevada congressional apportionment","How many electoral votes does Nevada have?"]', 'Based on the post-2020 census apportionment, Nevada is allocated 4 U.S. House districts, granting the state a total of 6 Electoral College votes.', 'https://www.nvsos.gov/sos/elections', 'Nevada Secretary of State', '2026-05-12', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('199386eb85081a51', 'NV', '["state"]', 'ballot_access', 'What is the single-subject rule for ballot initiatives in Nevada?', '["Can an initiative cover multiple topics in NV?","Single-subject requirement ballot measures","Nevada Constitution Article 19 restrictions"]', 'The Nevada Constitution mandates that any initiative petition must embrace only one subject and matters necessarily connected to it. If an initiative contains multiple unrelated subjects, it can be struck down by the courts.', 'https://www.leg.state.nv.us/Const/NVConst.html#Art19Sec1', 'Nevada Constitution Article 19 § 1', '2026-05-12', 'static', 'statute_citation', 'Ballot measure committees and Legal Counsel', 'batch_2026-05-13T02-18-53_nevada_full_v1'),
  ('b5ef62c62702b9b1', 'NV', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'How are election contests and protests adjudicated in Nevada?', '["Statement of Contest Nevada","Who hears election fraud disputes?","Contesting an election result NV"]', 'A defeated candidate may file a formal Statement of Contest within 5 days after a recount is completed or 14 days after the election. Contests for state and county offices are adjudicated by the district court, while contests involving the Governor or state legislators are decided by the Legislature.', 'https://www.leg.state.nv.us/nrs/nrs-293.html#NRS293Sec407', 'NRS 293.407', '2026-05-12', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-13T02-18-53_nevada_full_v1')
